// app/settings/page.tsx
import type { Metadata } from "next";
import Link from "next/link";
import Sidebar from "@/util/sidebar";

export const metadata: Metadata = {
  title: "Settings • DispatchNow",
};

function StatTile({
  title,
  desc,
  right,
}: {
  title: string;
  desc: string;
  right?: React.ReactNode;
}) {
  return (
    <div className="rounded-2xl border border-white/10 bg-white/5 p-5">
      <div className="flex items-start justify-between gap-4">
        <div>
          <div className="text-sm font-semibold text-[#D9D9D9]">{title}</div>
          <div className="mt-1 text-xs text-[#D9D9D9]/60">{desc}</div>
        </div>
        {right ? <div className="shrink-0">{right}</div> : null}
      </div>
    </div>
  );
}

function ButtonGhost({
  children,
  href,
}: {
  children: React.ReactNode;
  href?: string;
}) {
  const cls =
    "inline-flex items-center justify-center rounded-full border border-white/10 bg-white/5 px-4 py-2 text-xs text-white hover:bg-white/10 transition";
  return href ? (
    <Link href={href} className={cls}>
      {children}
    </Link>
  ) : (
    <button type="button" className={cls}>
      {children}
    </button>
  );
}

function Input({
  placeholder,
  defaultValue,
}: {
  placeholder: string;
  defaultValue?: string;
}) {
  return (
    <input
      defaultValue={defaultValue}
      placeholder={placeholder}
      className="w-full rounded-xl border border-white/10 bg-black/30 px-4 py-3 text-sm text-[#D9D9D9] placeholder:text-[#D9D9D9]/40 outline-none focus:border-white/20"
    />
  );
}

function Select({ options }: { options: string[] }) {
  return (
    <select className="w-full rounded-xl border border-white/10 bg-black/30 px-4 py-3 text-sm text-[#D9D9D9] outline-none focus:border-white/20">
      {options.map((o) => (
        <option key={o} value={o} className="bg-[#0b0b0c]">
          {o}
        </option>
      ))}
    </select>
  );
}

function Toggle({ defaultOn }: { defaultOn?: boolean }) {
  return (
    <label className="inline-flex cursor-pointer items-center gap-3">
      <span className="relative inline-flex h-6 w-11 items-center">
        <input
          defaultChecked={defaultOn}
          type="checkbox"
          className="peer sr-only"
        />
        <span className="absolute inset-0 rounded-full border border-white/10 bg-white/5 transition peer-checked:bg-white/10" />
        <span className="absolute left-1 h-4 w-4 rounded-full bg-[#D9D9D9]/70 transition peer-checked:translate-x-5 peer-checked:bg-[#D9D9D9]" />
      </span>
    </label>
  );
}

